import React, { useState } from "react";
import { Segment, Icon, Modal, Image } from "semantic-ui-react";
import tblMin from "../images/squid_poker_table-min.gif";
import tbl from "../images/squid_poker_table.gif";

export default function Slogan() {
  const [open, setOpen] = useState(false);
  const handleOpen = () => setOpen(true);
  const handleClose = () => setOpen(false);
  return (
    <div className="header">
      <Segment className="top-segment">
        <Segment className="top-segment inverted">
          <p className="slogan glitch">
            <span>
              Underwater poker degens coming soon to the Cardano network...
            </span>
            <span>
              Underwater poker degens coming soon to the Cardano network...
            </span>
            <strong style={{ opacity: 0 }}>
              Underwater poker degens coming soon to the Cardano network...
            </strong>
          </p>
        </Segment>
        <div className="social">
          <a href="https://discord.gg/q4K844da" className="social-icon">
            <Icon name="discord" />
            <span>discord</span>
          </a>
          <a href="https://twitter.com/squid_poker" className="social-icon">
            <Icon name="twitter" />
            <span>twitter</span>
          </a>
          <a href="/#" className="social-icon">
            <Icon name="file outline" />
            <span>white paper</span>
          </a>
        </div>
      </Segment>
      <Segment className="top-segment ">
        <p>
          Squid.poker will be the first provably fair No-Limit Texas hold 'em
          DAPP/game running on the Cardano network. All the important parts of
          the poker game will be managed automatically from a Cardano smart
          contract. (payouts, card randomization, player verification, etc.)
        </p>
        <br />
        <p>
          To play on the Squid.poker DAPP you will need to own 1 of our avatars
          which will generate a random number when you join a game and send your
          avatar into the smart contract. Once all players join the game all
          those random numbers will be combined into a unique number seed and
          then the cards will be dealt. This will make it impossible to cheat or
          exploit the game from our end or the players end.
        </p>
        <br />
        <p>
          We will be periodically releasing new Avatars, custom decks, table
          skins and more every few months with a limited supply for each of the
          customizations! You won't need to purchase a custom deck to play as
          everyone will be provided with a default deck/table layout. The only
          thing you will need is any of our avatars we release on our verified
          policies! All of our avatars and customizations will be 100% on-chain
          Cardano native assets.
        </p>
        <br />
      </Segment>
      <div className="poker-table">
        <img
          src={tblMin}
          alt="poker table"
          className="poker"
          onClick={handleOpen}
          role="presentation"
          aria-hidden="true"
        />
        <Modal
          open={open}
          size="large"
          className="pk"
          closeIcon
          onClose={handleClose}
        >
          <Image fluid src={tbl} alt="poker table" />
        </Modal>
      </div>
    </div>
  );
}
