import React from "react";
import { Transition, Button, List, Segment } from "semantic-ui-react";

export default function ExternalLinks() {
  const [visible, setVisible] = React.useState(false);
  function toggleVisibility() {
    setVisible(!visible);
  }
  return (
    <div>
      <Button basic fluid content="External Links" onClick={toggleVisibility} />
      <Transition
        visible={visible}
        animation="slide down"
        duration={500}
        unmountOnHide
      >
        <List
          as={Segment}
          divided
          relaxed
          style={{ textAlign: "left", paddingBottom: 10 }}
        >
          <List.Item>
            <List.Icon name="linkify" verticalAlign="middle" />
            <List.Content>
              <List.Header as="a">Semantic-Org/Semantic-UI</List.Header>
            </List.Content>
          </List.Item>
        </List>
      </Transition>
    </div>
  );
}
