import React from "react";
import { Container } from "semantic-ui-react";

const signs = ["clubs", "diamonds", "hearts", "spades"];
const types = [2, 3, 4, 5, 6, 7, 8, 9, 10, "ace", "king", "queen", "jack"];
const decks = [];
types.forEach((type) => {
  signs.forEach((sign) =>
    decks.push("/images/deck/" + type + "_of_" + sign + ".png")
  );
});
["black", "blue", "gray", "green", "purple", "red", "teal", "yellow"].forEach(
  (color) => decks.push("/images/deck/" + color + "_card_back.png")
);

export default function Decks() {
  return (
    <div>
      <h1 className="section-header">Decks</h1>
      <div className="avatars">
        {decks.map((card, idx) => (
          <div className="avatar" key={idx}>
            <img src={card} alt="card" />
          </div>
        ))}
      </div>
      <Container text textAlign="center">
        <p className="caption">
          There are 52 cards which includes 13 of each suit heart emoji, diamond
          emoji, club emoji, spade emoji + 8 different colored card backs with a
          supply of 4. By owning a single card from the OG Ocean deck you will
          own the entire custom deck! There is a max of 13 copies of each card
          for a total of 708! All of our custom decks will be equally limited to
          this same amount, so grab a card before they're all gone! Send 30 ₳ADA
          to the address below to unlock this special edition custom deck!
        </p>
      </Container>
    </div>
  );
}
