export default function Policies() {
  const [open, setOpen] = React.useState(false);
  function handleOpen() {
    setOpen(true);
  }
  function handleClose() {
    setOpen(false);
  }
  return (
    <div className="policies">
      <Modal open={open} onClose={handleClose} size="mini">
        <List divided relaxed>
          {policyIds.map((option, idx) => (
            <List.Item key={idx} className="relaxed">
              <a className="pid" href={option.link}>
                {option.text}
              </a>
            </List.Item>
          ))}
        </List>
      </Modal>
      <Button onClick={handleOpen} icon>
        <Icon name="sticky note outline" />
        <div className="text">Policy IDs</div>
      </Button>
    </div>
  );
}
